package controllers.amateur;

import entities.Evenement;
import javafx.fxml.FXML;
import javafx.scene.control.Label;
import javafx.scene.image.Image;
import javafx.scene.image.ImageView;
import javafx.scene.input.MouseEvent;

import java.io.File;
import java.time.LocalDateTime;
import java.time.format.DateTimeFormatter;
import java.util.function.Consumer;

public class EventCardController {

    private static final DateTimeFormatter DATE_FORMATTER = DateTimeFormatter.ofPattern("EEE, dd MMM yyyy HH:mm");
    private static final String BADGE_EXPOSITION_CLASS = "amateur-event-badge-exposition";
    private static final String BADGE_CONCERT_CLASS = "amateur-event-badge-concert";
    private static final String BADGE_SPECTACLE_CLASS = "amateur-event-badge-spectacle";
    private static final String BADGE_CONFERENCE_CLASS = "amateur-event-badge-conference";

    @FXML
    private ImageView coverImageView;

    @FXML
    private Label categoryBadgeLabel;

    @FXML
    private Label titleLabel;

    @FXML
    private Label dateLabel;

    @FXML
    private Label placeLabel;

    @FXML
    private Label statusLabel;

    @FXML
    private Label priceLabel;

    @FXML
    private Label descriptionLabel;

    private Evenement evenement;
    private Consumer<Evenement> detailHandler;

    public void setData(Evenement evenement) {
        this.evenement = evenement;
        String category = textOrDefault(evenement.getType(), "Evenement");
        categoryBadgeLabel.setText(category);
        applyCategoryBadgeStyle(category);
        titleLabel.setText(textOrDefault(evenement.getTitre(), "Evenement sans titre"));
        dateLabel.setText(formatDateTime(evenement.getDateDebut()));
        placeLabel.setText(formatCapacity(evenement.getCapaciteMax()));
        statusLabel.setText(textOrDefault(evenement.getStatut(), "A venir"));
        priceLabel.setText(formatPrice(evenement.getPrixTicket()));
        descriptionLabel.setText(textOrDefault(evenement.getDescription(), ""));
        applyImage(evenement.getImageCouverture());
    }

    public void setDetailHandler(Consumer<Evenement> detailHandler) {
        this.detailHandler = detailHandler;
    }

    @FXML
    private void onCardClick(MouseEvent event) {
        if (detailHandler != null && evenement != null) {
            detailHandler.accept(evenement);
        }
    }

    private void applyImage(String imageSource) {
        if (imageSource == null || imageSource.isBlank()) {
            coverImageView.setImage(null);
            return;
        }
        try {
            Image image;
            if (imageSource.startsWith("http://") || imageSource.startsWith("https://") || imageSource.startsWith("file:")) {
                image = new Image(imageSource, true);
            } else {
                image = new Image(new File(imageSource).toURI().toString(), true);
            }
            coverImageView.setImage(image.isError() ? null : image);
        } catch (Exception e) {
            coverImageView.setImage(null);
        }
    }

    private String formatDateTime(LocalDateTime dateTime) {
        return dateTime == null ? "Date non definie" : DATE_FORMATTER.format(dateTime);
    }

    private String formatCapacity(Integer capacity) {
        return capacity == null ? "Capacite non definie" : capacity + " places";
    }

    private String formatPrice(Double price) {
        return price == null ? "Prix non defini" : String.format("%.0f TND", price);
    }

    private String textOrDefault(String value, String fallback) {
        return value == null || value.isBlank() ? fallback : value;
    }

    private void applyCategoryBadgeStyle(String category) {
        categoryBadgeLabel.getStyleClass().removeAll(
                BADGE_EXPOSITION_CLASS,
                BADGE_CONCERT_CLASS,
                BADGE_SPECTACLE_CLASS,
                BADGE_CONFERENCE_CLASS
        );

        String normalized = category == null ? "" : category.trim().toLowerCase();
        switch (normalized) {
            case "exposition":
                categoryBadgeLabel.getStyleClass().add(BADGE_EXPOSITION_CLASS);
                break;
            case "concert":
                categoryBadgeLabel.getStyleClass().add(BADGE_CONCERT_CLASS);
                break;
            case "spectacle":
                categoryBadgeLabel.getStyleClass().add(BADGE_SPECTACLE_CLASS);
                break;
            case "conference":
            case "conférence":
                categoryBadgeLabel.getStyleClass().add(BADGE_CONFERENCE_CLASS);
                break;
            default:
                break;
        }
    }
}

package controllers.amateur;

import entities.Evenement;
import javafx.fxml.FXML;
import javafx.scene.control.Label;
import javafx.scene.image.Image;
import javafx.scene.image.ImageView;

import java.io.File;
import java.time.LocalDateTime;
import java.time.format.DateTimeFormatter;
import java.util.Locale;
import java.util.function.Consumer;

public class EventCardController {

    private static final DateTimeFormatter DATE_FORMATTER = DateTimeFormatter.ofPattern("EEE, dd MMM yyyy HH:mm");
    private static final String BADGE_EXPOSITION_CLASS = "amateur-event-badge-exposition";
    private static final String BADGE_CONCERT_CLASS = "amateur-event-badge-concert";
    private static final String BADGE_SPECTACLE_CLASS = "amateur-event-badge-spectacle";
    private static final String BADGE_CONFERENCE_CLASS = "amateur-event-badge-conference";

    @FXML
    private ImageView coverImageView;

    @FXML
    private Label categoryBadgeLabel;

    @FXML
    private Label titleLabel;

    @FXML
    private Label dateLabel;

    @FXML
    private Label placeLabel;

    @FXML
    private Label statusLabel;

    @FXML
    private Label priceLabel;

    @FXML
    private Label descriptionLabel;

    @FXML
    private Label scoreLabel;

    private Evenement evenement;
    private Consumer<Evenement> detailHandler;
    private double currentScoreOutOf10 = Double.NaN;

    public void setData(Evenement evenement) {
        this.evenement = evenement;
        String category = textOrDefault(evenement.getType(), "Evenement");
        categoryBadgeLabel.setText(category);
        applyCategoryBadgeStyle(category);
        titleLabel.setText(textOrDefault(evenement.getTitre(), "Evenement sans titre"));
        dateLabel.setText(formatDateTime(evenement.getDateDebut()));
        placeLabel.setText(formatCapacity(evenement.getCapaciteMax()));
        statusLabel.setText(textOrDefault(evenement.getStatut(), "A venir"));
        priceLabel.setText(formatPrice(evenement.getPrixTicket()));
        descriptionLabel.setText(textOrDefault(evenement.getDescription(), ""));
        scoreLabel.setText(formatScore(currentScoreOutOf10));
        applyImage(evenement.getImageCouverture());
    }

    public void setScore(double scoreOutOf10) {
        this.currentScoreOutOf10 = scoreOutOf10;
        if (scoreLabel != null) {
            if (!scoreLabel.getStyleClass().contains("amateur-event-score")) {
                scoreLabel.getStyleClass().add("amateur-event-score");
            }
            scoreLabel.setText(formatScore(scoreOutOf10));
        }
    }

    public void setDetailHandler(Consumer<Evenement> detailHandler) {
        this.detailHandler = detailHandler;
    }

    @FXML
    private void onCardClick() {
        if (detailHandler != null && evenement != null) {
            detailHandler.accept(evenement);
        }
    }

    private void applyImage(String imageSource) {
        if (imageSource == null || imageSource.isBlank()) {
            coverImageView.setImage(null);
            return;
        }
        try {
            Image image;
            if (imageSource.startsWith("http://") || imageSource.startsWith("https://") || imageSource.startsWith("file:")) {
                image = new Image(imageSource, true);
            } else {
                image = new Image(new File(imageSource).toURI().toString(), true);
            }
            coverImageView.setImage(image.isError() ? null : image);
        } catch (Exception e) {
            coverImageView.setImage(null);
        }
    }

    private String formatDateTime(LocalDateTime dateTime) {
        return dateTime == null ? "Date non definie" : DATE_FORMATTER.format(dateTime);
    }

    private String formatCapacity(Integer capacity) {
        return capacity == null ? "Capacite non definie" : capacity + " places";
    }

    private String formatPrice(Double price) {
        return price == null ? "Prix non defini" : String.format("%.0f TND", price);
    }

    private String formatScore(double scoreOutOf10) {
        if (Double.isNaN(scoreOutOf10) || scoreOutOf10 < 0) {
            return "Match IA: -";
        }
        return String.format(Locale.ROOT, "Match IA: %.1f/10", scoreOutOf10);
    }

    private String textOrDefault(String value, String fallback) {
        return value == null || value.isBlank() ? fallback : value;
    }

    private void applyCategoryBadgeStyle(String category) {
        categoryBadgeLabel.getStyleClass().removeAll(
                BADGE_EXPOSITION_CLASS,
                BADGE_CONCERT_CLASS,
                BADGE_SPECTACLE_CLASS,
                BADGE_CONFERENCE_CLASS
        );

        String normalized = category == null ? "" : category.trim().toLowerCase();
        switch (normalized) {
            case "exposition":
                categoryBadgeLabel.getStyleClass().add(BADGE_EXPOSITION_CLASS);
                break;
            case "concert":
                categoryBadgeLabel.getStyleClass().add(BADGE_CONCERT_CLASS);
                break;
            case "spectacle":
                categoryBadgeLabel.getStyleClass().add(BADGE_SPECTACLE_CLASS);
                break;
            case "conference":
            case "conférence":
                categoryBadgeLabel.getStyleClass().add(BADGE_CONFERENCE_CLASS);
                break;
            default:
                break;
        }
    }
}

package controllers.amateur;

import entities.Evenement;
import javafx.fxml.FXML;
import javafx.fxml.FXMLLoader;
import javafx.scene.Parent;
import javafx.scene.control.Label;
import javafx.scene.control.TextField;
import javafx.scene.control.ToggleButton;
import javafx.scene.layout.FlowPane;
import services.EvenementService;

import java.io.IOException;
import java.sql.SQLDataException;
import java.util.ArrayList;
import java.util.Comparator;
import java.util.List;
import java.util.Objects;
import java.util.function.Consumer;
import java.util.stream.Collectors;

import controllers.amateur.EventCardController;

public class EventsfrontController {

	@FXML
	private TextField searchField;

	@FXML
	private ToggleButton allTabButton;

	@FXML
	private ToggleButton expositionTabButton;

	@FXML
	private ToggleButton concertTabButton;

	@FXML
	private ToggleButton spectacleTabButton;

	@FXML
	private ToggleButton conferenceTabButton;

	@FXML
	private FlowPane eventsFlowPane;

	@FXML
	private Label emptyStateLabel;

	private final EvenementService evenementService = new EvenementService();
	private final List<Evenement> allEvents = new ArrayList<>();
	private String selectedCategory = "Tous";
	private Consumer<Evenement> detailNavigationHandler;

	@FXML
	public void initialize() {
		refreshEvents();
		onAllTabClick();
	}

	public void setDetailNavigationHandler(Consumer<Evenement> detailNavigationHandler) {
		this.detailNavigationHandler = detailNavigationHandler;
		// Cards are first rendered during initialize(), before parent injects navigation handler.
		// Re-apply filters so every visible card receives the click callback.
		if (!allEvents.isEmpty()) {
			applyFilters();
		}
	}

	@FXML
	private void onSearchClick() {
		applyFilters();
	}

	@FXML
	private void onAllTabClick() {
		selectedCategory = "Tous";
		setActiveTab(allTabButton);
		applyFilters();
	}

	@FXML
	private void onExpositionTabClick() {
		selectedCategory = "Exposition";
		setActiveTab(expositionTabButton);
		applyFilters();
	}

	@FXML
	private void onConcertTabClick() {
		selectedCategory = "Concert";
		setActiveTab(concertTabButton);
		applyFilters();
	}

	@FXML
	private void onSpectacleTabClick() {
		selectedCategory = "Spectacle";
		setActiveTab(spectacleTabButton);
		applyFilters();
	}

	@FXML
	private void onConferenceTabClick() {
		selectedCategory = "Conférence";
		setActiveTab(conferenceTabButton);
		applyFilters();
	}

	private void refreshEvents() {
		try {
			allEvents.clear();
			allEvents.addAll(evenementService.getAll());
			allEvents.sort(Comparator.comparing(Evenement::getDateDebut, Comparator.nullsLast(Comparator.naturalOrder())).reversed());
		} catch (SQLDataException e) {
			emptyStateLabel.setText("Impossible de charger les evenements.");
			emptyStateLabel.setVisible(true);
			emptyStateLabel.setManaged(true);
		}
	}

	private void applyFilters() {
		String search = searchField.getText() == null ? "" : searchField.getText().trim().toLowerCase();

		List<Evenement> filtered = allEvents.stream()
				.filter(event -> matchesCategory(event, selectedCategory))
				.filter(event -> matchesSearch(event, search))
				.collect(Collectors.toList());

		renderCards(filtered);
	}

	private boolean matchesCategory(Evenement event, String category) {
		if (category == null || "Tous".equalsIgnoreCase(category)) {
			return true;
		}
		return category.equalsIgnoreCase(safe(event.getType()));
	}

	private boolean matchesSearch(Evenement event, String search) {
		if (search.isEmpty()) {
			return true;
		}

		return contains(event.getTitre(), search)
				|| contains(event.getDescription(), search)
				|| contains(event.getType(), search)
				|| contains(event.getStatut(), search)
				|| contains(event.getPrixTicket() == null ? null : String.valueOf(event.getPrixTicket()), search);
	}

	private void renderCards(List<Evenement> events) {
		eventsFlowPane.getChildren().clear();

		for (Evenement event : events) {
			try {
				FXMLLoader loader = new FXMLLoader(Objects.requireNonNull(getClass().getResource("/views/amateur/components/event-card.fxml")));
				Parent card = loader.load();
				controllers.amateur.EventCardController controller = loader.getController();
				controller.setData(event);
				controller.setDetailHandler(detailNavigationHandler);
				eventsFlowPane.getChildren().add(card);
			} catch (IOException e) {
				emptyStateLabel.setText("Erreur lors de l'affichage des evenements.");
				emptyStateLabel.setVisible(true);
				emptyStateLabel.setManaged(true);
				return;
			}
		}

		boolean empty = events.isEmpty();
		emptyStateLabel.setVisible(empty);
		emptyStateLabel.setManaged(empty);
	}

	private void setActiveTab(ToggleButton activeButton) {
		ToggleButton[] buttons = {allTabButton, expositionTabButton, concertTabButton, spectacleTabButton, conferenceTabButton};
		for (ToggleButton button : buttons) {
			if (button != null) {
				button.getStyleClass().remove("active");
				button.setSelected(false);
			}
		}
		if (activeButton != null) {
			activeButton.getStyleClass().add("active");
			activeButton.setSelected(true);
		}
	}

	private boolean contains(String value, String search) {
		return value != null && value.toLowerCase().contains(search);
	}

	private String safe(String value) {
		return value == null ? "" : value;
	}
}

package controllers.amateur;

import entities.Evenement;
import javafx.fxml.FXML;
import javafx.fxml.FXMLLoader;
import javafx.application.Platform;
import javafx.scene.Parent;
import javafx.scene.control.Label;
import javafx.scene.control.TextField;
import javafx.scene.control.ToggleButton;
import javafx.animation.PauseTransition;
import javafx.util.Duration;
import javafx.scene.layout.FlowPane;
import services.EvenementService;
import services.EventAiSearchService;

import java.io.IOException;
import java.sql.SQLDataException;
import java.util.ArrayList;
import java.util.Comparator;
import java.util.List;
import java.util.Objects;
import java.util.concurrent.CompletableFuture;
import java.util.concurrent.ExecutorService;
import java.util.concurrent.Executors;
import java.util.concurrent.atomic.AtomicLong;
import java.util.function.Consumer;
import java.util.stream.Collectors;

public class EventsfrontController {

	@FXML
	private TextField searchField;

	@FXML
	private ToggleButton allTabButton;

	@FXML
	private ToggleButton expositionTabButton;

	@FXML
	private ToggleButton concertTabButton;

	@FXML
	private ToggleButton spectacleTabButton;

	@FXML
	private ToggleButton conferenceTabButton;

	@FXML
	private FlowPane eventsFlowPane;

	@FXML
	private Label emptyStateLabel;

	private final EvenementService evenementService = new EvenementService();
	private final EventAiSearchService aiSearchService = new EventAiSearchService();
	private final List<Evenement> allEvents = new ArrayList<>();
	private final AtomicLong searchSequence = new AtomicLong(0L);
	private final ExecutorService searchExecutor = Executors.newSingleThreadExecutor(runnable -> {
		Thread thread = new Thread(runnable, "event-ai-search");
		thread.setDaemon(true);
		return thread;
	});
	private final PauseTransition searchDebounce = new PauseTransition(Duration.millis(280));
	private String selectedCategory = "Tous";
	private Consumer<Evenement> detailNavigationHandler;

	@FXML
	public void initialize() {
		searchDebounce.setOnFinished(event -> triggerSearch(searchField.getText()));
		searchField.textProperty().addListener((observable, oldValue, newValue) -> {
			searchDebounce.stop();
			searchDebounce.playFromStart();
		});
		searchField.setOnAction(event -> triggerSearch(searchField.getText()));

		refreshEvents();
	}

	public void setDetailNavigationHandler(Consumer<Evenement> detailNavigationHandler) {
		this.detailNavigationHandler = detailNavigationHandler;
		// Cards are first rendered during initialize(), before parent injects navigation handler.
		// Re-run the search so every visible card receives the click callback.
		if (!allEvents.isEmpty()) {
			triggerSearch(searchField.getText());
		}
	}

	@FXML
	private void onSearchClick() {
		triggerSearch(searchField.getText());
	}

	@FXML
	private void onAllTabClick() {
		selectedCategory = "Tous";
		setActiveTab(allTabButton);
		triggerSearch(searchField.getText());
	}

	@FXML
	private void onExpositionTabClick() {
		selectedCategory = "Exposition";
		setActiveTab(expositionTabButton);
		triggerSearch(searchField.getText());
	}

	@FXML
	private void onConcertTabClick() {
		selectedCategory = "Concert";
		setActiveTab(concertTabButton);
		triggerSearch(searchField.getText());
	}

	@FXML
	private void onSpectacleTabClick() {
		selectedCategory = "Spectacle";
		setActiveTab(spectacleTabButton);
		triggerSearch(searchField.getText());
	}

	@FXML
	private void onConferenceTabClick() {
		selectedCategory = "Conférence";
		setActiveTab(conferenceTabButton);
		triggerSearch(searchField.getText());
	}

	private void refreshEvents() {
		try {
			allEvents.clear();
			allEvents.addAll(evenementService.getAll());
			allEvents.sort(Comparator.comparing(Evenement::getDateDebut, Comparator.nullsLast(Comparator.naturalOrder())).reversed());
			triggerSearch(searchField.getText());
		} catch (SQLDataException e) {
			emptyStateLabel.setText("Impossible de charger les evenements.");
			emptyStateLabel.setVisible(true);
			emptyStateLabel.setManaged(true);
		}
	}

	private void triggerSearch(String rawQuery) {
		String query = rawQuery == null ? "" : rawQuery.trim();
		long sequence = searchSequence.incrementAndGet();

		CompletableFuture
				.supplyAsync(() -> searchEvents(query), searchExecutor)
				.thenAccept(results -> Platform.runLater(() -> {
					if (sequence != searchSequence.get()) {
						return;
					}
					renderCards(results);
				}))
				.exceptionally(ex -> {
					Platform.runLater(() -> {
						if (sequence != searchSequence.get()) {
							return;
						}
						emptyStateLabel.setText("La recherche IA est temporairement indisponible.");
						emptyStateLabel.setVisible(true);
						emptyStateLabel.setManaged(true);
					});
					return null;
				});
	}

	private List<EventAiSearchService.RankedEvent> searchEvents(String query) {
		List<Evenement> scopedEvents = allEvents.stream()
				.filter(event -> matchesCategory(event, selectedCategory))
				.collect(Collectors.toList());

		if (query.isBlank()) {
			return scopedEvents.stream()
					.map(event -> new EventAiSearchService.RankedEvent(event, Double.NaN))
					.collect(Collectors.toList());
		}

		return aiSearchService.rankEvents(scopedEvents, query);
	}

	private boolean matchesCategory(Evenement event, String category) {
		if (category == null || "Tous".equalsIgnoreCase(category)) {
			return true;
		}
		return category.equalsIgnoreCase(safe(event.getType()));
	}

	private void renderCards(List<EventAiSearchService.RankedEvent> rankedEvents) {
		eventsFlowPane.getChildren().clear();

		for (EventAiSearchService.RankedEvent rankedEvent : rankedEvents) {
			Evenement event = rankedEvent.event();
			try {
				FXMLLoader loader = new FXMLLoader(Objects.requireNonNull(getClass().getResource("/views/amateur/components/event-card.fxml")));
				Parent card = loader.load();
				EventCardController controller = loader.getController();
				controller.setData(event);
				controller.setScore(rankedEvent.scoreOutOf10());
				controller.setDetailHandler(detailNavigationHandler);
				eventsFlowPane.getChildren().add(card);
			} catch (IOException e) {
				emptyStateLabel.setText("Erreur lors de l'affichage des evenements.");
				emptyStateLabel.setVisible(true);
				emptyStateLabel.setManaged(true);
				return;
			}
		}

		boolean empty = rankedEvents.isEmpty();
		emptyStateLabel.setVisible(empty);
		emptyStateLabel.setManaged(empty);
	}

	private void setActiveTab(ToggleButton activeButton) {
		ToggleButton[] buttons = {allTabButton, expositionTabButton, concertTabButton, spectacleTabButton, conferenceTabButton};
		for (ToggleButton button : buttons) {
			if (button != null) {
				button.getStyleClass().remove("active");
				button.setSelected(false);
			}
		}
		if (activeButton != null) {
			activeButton.getStyleClass().add("active");
			activeButton.setSelected(true);
		}
	}

	private boolean contains(String value, String search) {
		return value != null && value.toLowerCase().contains(search);
	}

	private String safe(String value) {
		return value == null ? "" : value;
	}
}

package services;

import entities.Evenement;

import java.io.IOException;
import java.net.URI;
import java.net.http.HttpClient;
import java.net.http.HttpRequest;
import java.net.http.HttpResponse;
import java.nio.charset.StandardCharsets;
import java.nio.file.Files;
import java.nio.file.Path;
import java.util.ArrayList;
import java.util.Arrays;
import java.util.Comparator;
import java.util.LinkedHashSet;
import java.util.List;
import java.util.Locale;
import java.util.Map;
import java.util.Objects;
import java.util.Properties;
import java.util.Set;
import java.util.concurrent.ConcurrentHashMap;
import java.util.stream.Collectors;

public class EventAiSearchService {

    private static final String DEFAULT_HOST = "http://localhost:11434";
    private static final String DEFAULT_EMBEDDING_MODEL = "nomic-embed-text:latest";
    private static final String DEFAULT_CONFIG_FILE = "config/ollama.local.properties";

    private static final String HOST_PROPERTY = "ollama.host";
    private static final String EMBEDDING_MODEL_PROPERTY = "ollama.embedding.model";
    private static final String CONFIG_PATH_PROPERTY = "ollama.configPath";

    private static final String HOST_ENV = "OLLAMA_HOST";
    private static final String EMBEDDING_MODEL_ENV = "OLLAMA_EMBEDDING_MODEL";
    private static final String CONFIG_PATH_ENV = "OLLAMA_CONFIG_PATH";

    private final HttpClient httpClient;
    private final SearchConfig config;
    private final Map<String, double[]> embeddingCache = new ConcurrentHashMap<>();
    private final Map<String, double[]> eventEmbeddingCache = new ConcurrentHashMap<>();

    public EventAiSearchService() {
        this.httpClient = HttpClient.newBuilder().build();
        this.config = loadConfig();
    }

    public List<RankedEvent> rankEvents(List<Evenement> events, String query) {
        List<Evenement> safeEvents = events == null ? List.of() : events;
        String normalizedQuery = normalize(query);

        if (safeEvents.isEmpty()) {
            return List.of();
        }

        if (normalizedQuery.isBlank()) {
            return safeEvents.stream()
                    .map(event -> new RankedEvent(event, Double.NaN))
                    .sorted(defaultComparator())
                    .collect(Collectors.toList());
        }

        double[] queryEmbedding = getEmbeddingOrNull(normalizedQuery);
        List<RankedEvent> ranked = new ArrayList<>(safeEvents.size());

        for (Evenement event : safeEvents) {
            double score = queryEmbedding == null
                    ? heuristicScore(normalizedQuery, event)
                    : scoreAgainstEmbedding(normalizedQuery, queryEmbedding, event);
            ranked.add(new RankedEvent(event, score));
        }

        ranked.sort(Comparator
                .comparingDouble(RankedEvent::score).reversed()
                .thenComparing(rankedEvent -> safeDateKey(rankedEvent.event()), Comparator.reverseOrder())
                .thenComparing(rankedEvent -> safeText(rankedEvent.event().getTitre())));

        return ranked;
    }

    private double scoreAgainstEmbedding(String query, double[] queryEmbedding, Evenement event) {
        double[] eventEmbedding = getEventEmbedding(event);
        if (queryEmbedding == null || eventEmbedding == null) {
            return heuristicScore(query, event);
        }

        double cosine = cosineSimilarity(queryEmbedding, eventEmbedding);
        if (Double.isNaN(cosine) || Double.isInfinite(cosine)) {
            return heuristicScore(query, event);
        }

        double normalized = Math.max(0d, (cosine + 1d) / 2d);
        return roundScore(normalized * 10d);
    }

    private double[] getEventEmbedding(Evenement event) {
        if (event == null) {
            return null;
        }

        String cacheKey = event.getId() == null
                ? buildEventText(event)
                : event.getId() + "::" + buildEventText(event);

        return eventEmbeddingCache.computeIfAbsent(cacheKey, key -> getEmbeddingOrNull(buildEventText(event)));
    }

    private double[] getEmbeddingOrNull(String text) {
        String normalized = normalize(text);
        if (normalized.isBlank()) {
            return null;
        }

        double[] cached = embeddingCache.get(normalized);
        if (cached != null) {
            return cached;
        }

        try {
            double[] embedding = fetchEmbedding(normalized);
            if (embedding != null && embedding.length > 0) {
                embeddingCache.put(normalized, embedding);
            }
            return embedding;
        } catch (Exception e) {
            return null;
        }
    }

    private double[] fetchEmbedding(String input) throws IOException, InterruptedException {
        String payload = "{\"model\":\"" + escapeJson(config.embeddingModel()) + "\",\"prompt\":\"" + escapeJson(input) + "\"}";

        HttpRequest request = HttpRequest.newBuilder()
                .uri(URI.create(config.host() + "/api/embeddings"))
                .header("Content-Type", "application/json")
                .POST(HttpRequest.BodyPublishers.ofString(payload, StandardCharsets.UTF_8))
                .build();

        HttpResponse<String> response = httpClient.send(request, HttpResponse.BodyHandlers.ofString(StandardCharsets.UTF_8));
        if (response.statusCode() < 200 || response.statusCode() >= 300) {
            return null;
        }

        return parseEmbedding(response.body());
    }

    private double[] parseEmbedding(String body) {
        if (body == null || body.isBlank()) {
            return null;
        }

        int keyIndex = body.indexOf("\"embedding\"");
        if (keyIndex < 0) {
            return null;
        }

        int arrayStart = body.indexOf('[', keyIndex);
        int arrayEnd = findMatchingBracket(body, arrayStart);
        if (arrayStart < 0 || arrayEnd <= arrayStart) {
            return null;
        }

        String rawArray = body.substring(arrayStart + 1, arrayEnd).trim();
        if (rawArray.isBlank()) {
            return null;
        }

        String[] parts = rawArray.split(",");
        double[] embedding = new double[parts.length];
        int count = 0;

        for (String part : parts) {
            String token = part.trim();
            if (token.isEmpty()) {
                continue;
            }

            try {
                embedding[count++] = Double.parseDouble(token);
            } catch (NumberFormatException ignored) {
                return null;
            }
        }

        return count == embedding.length ? embedding : Arrays.copyOf(embedding, count);
    }

    private int findMatchingBracket(String text, int openIndex) {
        if (openIndex < 0 || openIndex >= text.length() || text.charAt(openIndex) != '[') {
            return -1;
        }

        int depth = 0;
        for (int i = openIndex; i < text.length(); i++) {
            char c = text.charAt(i);
            if (c == '[') {
                depth++;
            } else if (c == ']') {
                depth--;
                if (depth == 0) {
                    return i;
                }
            }
        }
        return -1;
    }

    private double heuristicScore(String query, Evenement event) {
        String eventText = buildEventText(event);
        Set<String> queryTokens = tokenize(query);
        if (queryTokens.isEmpty()) {
            return 0d;
        }

        Set<String> eventTokens = tokenize(eventText);
        if (eventTokens.isEmpty()) {
            return 0d;
        }

        long overlap = queryTokens.stream().filter(eventTokens::contains).count();
        double ratio = (double) overlap / (double) Math.max(queryTokens.size(), 1);
        double titleBonus = fuzzyContains(safeText(event == null ? null : event.getTitre()), query) ? 0.25d : 0d;
        double typeBonus = fuzzyContains(safeText(event == null ? null : event.getType()), query) ? 0.15d : 0d;
        return roundScore(Math.min(1d, ratio + titleBonus + typeBonus) * 10d);
    }

    private boolean fuzzyContains(String source, String query) {
        return !source.isBlank() && !query.isBlank() && source.contains(query);
    }

    private Set<String> tokenize(String text) {
        if (text == null || text.isBlank()) {
            return Set.of();
        }

        String normalized = text.toLowerCase(Locale.ROOT)
                .replaceAll("[^a-z0-9à-ÿ]+", " ")
                .trim();
        if (normalized.isBlank()) {
            return Set.of();
        }

        Set<String> tokens = new LinkedHashSet<>();
        for (String token : normalized.split("\\s+")) {
            if (!token.isBlank()) {
                tokens.add(token);
            }
        }
        return tokens;
    }

    private String buildEventText(Evenement event) {
        if (event == null) {
            return "";
        }

        return String.join(" ",
                safeText(event.getTitre()),
                safeText(event.getDescription()),
                safeText(event.getType()),
                safeText(event.getStatut()));
    }

    private double cosineSimilarity(double[] left, double[] right) {
        if (left == null || right == null || left.length == 0 || right.length == 0) {
            return Double.NaN;
        }

        int size = Math.min(left.length, right.length);
        double dot = 0d;
        double leftNorm = 0d;
        double rightNorm = 0d;

        for (int i = 0; i < size; i++) {
            dot += left[i] * right[i];
            leftNorm += left[i] * left[i];
            rightNorm += right[i] * right[i];
        }

        if (leftNorm == 0d || rightNorm == 0d) {
            return Double.NaN;
        }

        return dot / (Math.sqrt(leftNorm) * Math.sqrt(rightNorm));
    }

    private Comparator<RankedEvent> defaultComparator() {
        return Comparator
                .comparing((RankedEvent rankedEvent) -> safeDateKey(rankedEvent.event()), Comparator.reverseOrder())
                .thenComparing(rankedEvent -> safeText(rankedEvent.event().getTitre()));
    }

    private String safeDateKey(Evenement event) {
        if (event == null) {
            return "";
        }
        if (event.getDateDebut() != null) {
            return event.getDateDebut().toString();
        }
        if (event.getDateCreation() != null) {
            return event.getDateCreation().toString();
        }
        return event.getId() == null ? "" : String.format(Locale.ROOT, "%010d", event.getId());
    }

    private String normalize(String value) {
        return value == null ? "" : value.trim().toLowerCase(Locale.ROOT);
    }

    private String safeText(String value) {
        return value == null ? "" : value.trim();
    }

    private double roundScore(double value) {
        return Math.max(0d, Math.min(10d, Math.round(value * 10d) / 10d));
    }

    private String escapeJson(String value) {
        if (value == null) {
            return "";
        }
        return value
                .replace("\\", "\\\\")
                .replace("\"", "\\\"")
                .replace("\n", " ")
                .replace("\r", " ")
                .replace("\t", " ");
    }

    private SearchConfig loadConfig() {
        Properties properties = new Properties();

        Path configPath = resolveConfigPath();
        if (Files.exists(configPath)) {
            try {
                try (var reader = Files.newBufferedReader(configPath, StandardCharsets.UTF_8)) {
                    properties.load(reader);
                }
            } catch (IOException ignored) {
                // Fall back to defaults and environment variables.
            }
        }

        String host = firstNonBlank(
                System.getProperty(HOST_PROPERTY),
                System.getenv(HOST_ENV),
                properties.getProperty(HOST_PROPERTY),
                DEFAULT_HOST);

        String embeddingModel = firstNonBlank(
                System.getProperty(EMBEDDING_MODEL_PROPERTY),
                System.getenv(EMBEDDING_MODEL_ENV),
                properties.getProperty(EMBEDDING_MODEL_PROPERTY),
                DEFAULT_EMBEDDING_MODEL);

        return new SearchConfig(host, embeddingModel);
    }

    private Path resolveConfigPath() {
        String systemPath = System.getProperty(CONFIG_PATH_PROPERTY);
        if (systemPath != null && !systemPath.isBlank()) {
            return Path.of(systemPath);
        }

        String envPath = System.getenv(CONFIG_PATH_ENV);
        if (envPath != null && !envPath.isBlank()) {
            return Path.of(envPath);
        }

        return Path.of(DEFAULT_CONFIG_FILE);
    }

    @SafeVarargs
    private <T> T firstNonBlank(T... values) {
        for (T value : values) {
            if (value instanceof String stringValue && !stringValue.isBlank()) {
                return value;
            }
        }
        return values.length == 0 ? null : values[values.length - 1];
    }

    public record RankedEvent(Evenement event, double scoreOutOf10) {
        public double score() {
            return scoreOutOf10;
        }
    }

    private record SearchConfig(String host, String embeddingModel) {
        private SearchConfig {
            host = Objects.requireNonNullElse(host, DEFAULT_HOST).trim();
            embeddingModel = Objects.requireNonNullElse(embeddingModel, DEFAULT_EMBEDDING_MODEL).trim();
            if (host.isBlank()) {
                host = DEFAULT_HOST;
            }
            if (embeddingModel.isBlank()) {
                embeddingModel = DEFAULT_EMBEDDING_MODEL;
            }
        }
    }
}

