}

/* Amateur front-office theme placeholders */
.amateur-root {
    -fx-background-color: #eaf3ff;
}

.amateur-shell {
    -fx-background-color: transparent;
}

.amateur-page-card {
    -fx-background-color: white;
    -fx-background-radius: 12;
    -fx-border-color: #e2e8f0;
    -fx-border-radius: 12;
}

.amateur-left-sidebar {
    -fx-background-color: transparent;
}
.amateur-root {
    -fx-font-family: "Segoe UI", Arial, sans-serif;
    -fx-background-color: #eaf3ff;
}

.amateur-root .label {
    -fx-text-fill: #2f3e52;
}

.amateur-root .scroll-pane,
.amateur-root .scroll-pane > .viewport,
.amateur-root .scroll-pane .content,
.amateur-shell,
.amateur-page-host,
.amateur-content-column {
    -fx-background-color: transparent;
}

.amateur-scroll {
    -fx-background: #eaf3ff;
    -fx-background-color: transparent;
}

.amateur-navbar {
    -fx-background-color: #f8f9fb;
    -fx-border-color: #d9dce3;
    -fx-border-width: 0 0 1 0;
}

.amateur-search-field {
    -fx-background-color: #f4f5f7;
    -fx-border-color: #c8cdd7;
    -fx-border-radius: 6;
    -fx-background-radius: 6;
    -fx-padding: 0 12 0 12;
    -fx-prompt-text-fill: #9aa3b2;
}

.amateur-root .button,
.amateur-root .menu-button,
.amateur-root .combo-box-base,
.amateur-root .date-picker,
.amateur-root .text-field,
.amateur-root .text-area {
    -fx-background-radius: 8;
    -fx-border-radius: 8;
}

.amateur-icon-button,
.amateur-nav-link,
.amateur-nav-menu,
.amateur-avatar-menu,
.avatar-menu {
    -fx-background-color: #eef1f5;
    -fx-border-color: #d4d9e1;
    -fx-text-fill: #3b4250;
    -fx-font-weight: 700;
}

/* Professional Notifications Menu Button */
.notifications-menu-button {
    -fx-padding: 0 10 0 10;
    -fx-background-radius: 18;
    -fx-border-radius: 18;
    -fx-background-color: #f0f2ff;
    -fx-border-color: #d4d9e1;
    -fx-text-fill: #4252b8;
    -fx-font-weight: 700;
    -fx-font-size: 16px;
    -fx-effect: dropshadow(gaussian, rgba(66, 82, 184, 0.12), 8, 0, 0, 2);
}

.notifications-menu-button:hover {
    -fx-background-color: #e8ebff;
    -fx-border-color: #c4cbe1;
    -fx-effect: dropshadow(gaussian, rgba(66, 82, 184, 0.18), 12, 0, 0, 3);
}

.notifications-menu-button:showing {
    -fx-background-color: #e3e8ff;
    -fx-border-color: #bfc6ff;
    -fx-effect: dropshadow(gaussian, rgba(66, 82, 184, 0.20), 14, 0, 0, 4);
}

.notifications-menu-button > .arrow-button,
.notifications-menu-button > .arrow-button > .arrow {
    -fx-padding: 0;
    -fx-background-color: transparent;
}

/* Professional Notifications Context Menu */
.context-menu.notifications-context-menu {
    -fx-background-color: #ffffff;
    -fx-background-radius: 14;
    -fx-border-color: #d9dce3;
    -fx-border-radius: 14;
    -fx-border-width: 1;
    -fx-padding: 8;
    -fx-effect: dropshadow(gaussian, rgba(31, 45, 70, 0.18), 20, 0.16, 0, 6);
}

.context-menu.notifications-context-menu .menu-item {
    -fx-background-color: transparent;
    -fx-background-radius: 10;
    -fx-padding: 10 14 10 14;
    -fx-font-size: 13px;
    -fx-text-fill: #243146;
}

.context-menu.notifications-context-menu .menu-item:hover,
.context-menu.notifications-context-menu .menu-item:focused {
    -fx-background-color: #f0f2ff;
    -fx-background-radius: 10;
}

.context-menu.notifications-context-menu .menu-item > .label {
    -fx-text-fill: #243146;
    -fx-font-size: 13px;
    -fx-font-weight: 600;
}

/* Notification item headers */
.context-menu.notifications-context-menu .menu-item.notifications-header {
    -fx-font-weight: 700;
    -fx-text-fill: #1f2d3d;
    -fx-padding: 12 14 8 14;
    -fx-font-size: 14px;
}

.context-menu.notifications-context-menu .menu-item.notifications-header:hover,
.context-menu.notifications-context-menu .menu-item.notifications-header:focused {
    -fx-background-color: transparent;
}

/* Separator in notifications menu */
.context-menu.notifications-context-menu .separator {
    -fx-padding: 4 0;
}

.context-menu.notifications-context-menu .separator:horizontal .line {
    -fx-border-color: #e2e8f2;
    -fx-border-width: 1 0 0 0;
}

.notifications-item {
    -fx-padding: 8 12 8 12;
    -fx-font-size: 12px;
}

/* Dark mode notifications menu */
.amateur-root.dark-mode .notifications-menu-button {
    -fx-background-color: #324261;
    -fx-border-color: #46557a;
    -fx-text-fill: #8ea8ff;
    -fx-effect: dropshadow(gaussian, rgba(142, 168, 255, 0.12), 8, 0, 0, 2);
}

.amateur-root.dark-mode .notifications-menu-button:hover {
    -fx-background-color: #3a4a72;
    -fx-border-color: #566780;
    -fx-effect: dropshadow(gaussian, rgba(142, 168, 255, 0.18), 12, 0, 0, 3);
}

.amateur-root.dark-mode .notifications-menu-button:showing {
    -fx-background-color: #404f7e;
    -fx-border-color: #6878a0;
    -fx-effect: dropshadow(gaussian, rgba(142, 168, 255, 0.20), 14, 0, 0, 4);
}

.amateur-root.dark-mode .context-menu.notifications-context-menu {
    -fx-background-color: #1f2a40;
    -fx-border-color: #3f4b6c;
    -fx-effect: dropshadow(gaussian, rgba(0, 0, 0, 0.30), 20, 0.16, 0, 6);
}

.amateur-root.dark-mode .context-menu.notifications-context-menu .menu-item {
    -fx-text-fill: #dbe6ff;
}

.amateur-root.dark-mode .context-menu.notifications-context-menu .menu-item:hover,
.amateur-root.dark-mode .context-menu.notifications-context-menu .menu-item:focused {
    -fx-background-color: #2d3956;
}

.amateur-root.dark-mode .context-menu.notifications-context-menu .menu-item.notifications-header {
    -fx-text-fill: #edf2ff;
}

.amateur-root.dark-mode .context-menu.notifications-context-menu .separator:horizontal .line {
    -fx-border-color: #3f4b6c;
}

/* Presentable notifications dropdown rows */
.context-menu.notifications-context-menu {
    -fx-min-width: 360;
    -fx-max-width: 380;
}

.context-menu.notifications-context-menu .menu-item {
    -fx-padding: 0;
}

.context-menu.notifications-context-menu .menu-item.notifications-item {
    -fx-padding: 0;
}

.context-menu.notifications-context-menu .menu-item.notifications-item > .label {
    -fx-padding: 0;
}

.context-menu.notifications-context-menu .menu-item.notifications-item:disabled {
    -fx-opacity: 1;
}

.notifications-item-content {
    -fx-padding: 10 12 10 12;
    -fx-background-color: linear-gradient(to bottom, #fbfcff, #f4f7ff);
    -fx-border-color: #e0e8f6;
    -fx-border-width: 1;
    -fx-background-radius: 10;
    -fx-border-radius: 10;
}

.context-menu.notifications-context-menu .menu-item.notifications-item:hover .notifications-item-content,
.context-menu.notifications-context-menu .menu-item.notifications-item:focused .notifications-item-content {
    -fx-background-color: linear-gradient(to bottom, #f2f6ff, #eaf0ff);
    -fx-border-color: #cfdafb;
}

.notifications-item-title {
    -fx-text-fill: #1f2f46;
    -fx-font-size: 13px;
    -fx-font-weight: 700;
}

.notifications-item-message {
    -fx-text-fill: #5f718b;
    -fx-font-size: 12px;
}

.notifications-item-time {
    -fx-text-fill: #7a8ca4;
    -fx-font-size: 11px;
    -fx-font-style: italic;
}

.notifications-empty-row {
    -fx-padding: 8 4 8 4;
}

.notifications-empty-label {
    -fx-text-fill: #70839d;
    -fx-font-size: 12px;
    -fx-font-style: italic;
}

.amateur-root.dark-mode .notifications-item-content {
    -fx-background-color: linear-gradient(to bottom, #2c3d5b, #273854);
    -fx-border-color: #3c5074;
}

.amateur-root.dark-mode .context-menu.notifications-context-menu .menu-item.notifications-item:hover .notifications-item-content,
.amateur-root.dark-mode .context-menu.notifications-context-menu .menu-item.notifications-item:focused .notifications-item-content {
    -fx-background-color: linear-gradient(to bottom, #344867, #2f4160);
    -fx-border-color: #4c638d;
}

.amateur-root.dark-mode .notifications-item-title {
