    -fx-effect: dropshadow(gaussian, rgba(35, 54, 87, 0.08), 18, 0.10, 0, 4);
}

.event-title {
    -fx-font-size: 30px;
    -fx-font-weight: 700;
    -fx-text-fill: #152238;
}

.event-chip {
    -fx-background-color: #eef2ff;
    -fx-border-color: #d6defa;
    -fx-border-width: 1;
    -fx-text-fill: #2f3b94;
    -fx-padding: 5 10 5 10;
    -fx-background-radius: 999;
    -fx-border-radius: 999;
    -fx-font-size: 11px;
    -fx-font-weight: 700;
}

.event-chip-type {
    -fx-background-color: #eef2ff;
    -fx-border-color: #d5ddff;
    -fx-text-fill: #3740a1;
}

.event-chip-status {
    -fx-background-color: #e8f8f3;
    -fx-border-color: #c7ebdf;
    -fx-text-fill: #0f7e5a;
}

.event-description-title {
    -fx-font-size: 13px;
    -fx-font-weight: 700;
    -fx-text-fill: #3f5472;
    -fx-padding: 4 0 0 0;
}

.event-description {
    -fx-text-fill: #5f728e;
    -fx-font-size: 14px;
    -fx-line-spacing: 2px;
}

.event-stat-label {
    -fx-text-fill: #60728d;
    -fx-font-size: 12px;
    -fx-font-weight: 700;
}

.event-stat-value {
    -fx-text-fill: #1f2f46;
    -fx-font-size: 13px;
    -fx-font-weight: 600;
}

.event-price-value {
    -fx-text-fill: #09996a;
    -fx-font-weight: 700;
}

.event-location-info {
    -fx-padding: 4 0 0 0;
}

.event-location-label {
    -fx-font-size: 12px;
    -fx-font-weight: 700;
    -fx-text-fill: #4d6180;
}

.ticket-section-card {
    -fx-spacing: 12;
    -fx-background-color: white;
    -fx-background-radius: 14;
    -fx-border-color: #e1e8f4;
    -fx-border-radius: 14;
    -fx-effect: dropshadow(gaussian, rgba(35, 54, 87, 0.07), 16, 0.10, 0, 3);
}

.ticket-section-title {
    -fx-font-size: 19px;
    -fx-font-weight: 700;
    -fx-text-fill: #16253b;
}

.ticket-count-chip {
    -fx-background-color: #edf2ff;
    -fx-border-color: #d6defa;
    -fx-border-width: 1;
    -fx-background-radius: 999;
    -fx-border-radius: 999;
    -fx-padding: 4 10 4 10;
    -fx-text-fill: #3341a0;
    -fx-font-size: 12px;
    -fx-font-weight: 700;
}

.ticket-row {
    -fx-background-color: #f8fbff;
    -fx-background-radius: 12;
    -fx-border-color: #dce6f4;
    -fx-border-radius: 12;
    -fx-padding: 12 14 12 14;
    -fx-alignment: center-left;
}

.ticket-row:hover {
    -fx-background-color: #f1f6ff;
    -fx-border-color: #cfdcf4;
}

.ticket-info {
    -fx-padding: 0;
}

.ticket-title {
    -fx-font-size: 14px;
    -fx-font-weight: 700;
    -fx-text-fill: #15263c;
}

.ticket-subtitle {
    -fx-font-size: 12px;
    -fx-text-fill: #6d7f97;
}

.ticket-actions {
    -fx-alignment: center-right;
}

.ticket-action-primary,
.ticket-action-secondary {
    -fx-font-size: 12px;
    -fx-font-weight: 700;
    -fx-background-radius: 9;
    -fx-border-radius: 9;
    -fx-padding: 7 12 7 12;
    -fx-cursor: hand;
}

.ticket-action-primary {
    -fx-background-color: linear-gradient(to bottom, #4654da, #3546c8);
    -fx-text-fill: white;
}

.ticket-action-primary:hover {
    -fx-background-color: linear-gradient(to bottom, #4f5fe3, #3d50d4);
}

.ticket-action-primary:disabled {
    -fx-background-color: #a4afc4;
    -fx-text-fill: #f5f7fb;
    -fx-cursor: default;
}

.ticket-action-secondary {
    -fx-background-color: #f3f6fb;
    -fx-border-color: #d4ddea;
    -fx-border-width: 1;
    -fx-text-fill: #2f435f;
}

.ticket-action-secondary:hover {
    -fx-background-color: #eaf0f8;
}

.amateur-root.dark-mode .event-cover-box,
.amateur-root.dark-mode .event-detail-header-card,
.amateur-root.dark-mode .ticket-section-card {
    -fx-background-color: #243149;
    -fx-border-color: #324262;
}

.amateur-root.dark-mode .event-title,
.amateur-root.dark-mode .ticket-section-title,
.amateur-root.dark-mode .ticket-title,
.amateur-root.dark-mode .event-stat-value {
    -fx-text-fill: #edf2ff;
}

.amateur-root.dark-mode .event-description,
.amateur-root.dark-mode .event-stat-label,
.amateur-root.dark-mode .event-location-label,
.amateur-root.dark-mode .ticket-subtitle {
    -fx-text-fill: #b8c5dc;
}

.amateur-root.dark-mode .event-chip,
.amateur-root.dark-mode .ticket-count-chip {
    -fx-background-color: #314263;
    -fx-border-color: #41557b;
    -fx-text-fill: #d6e4ff;
}

.amateur-root.dark-mode .ticket-row {
    -fx-background-color: #2a3954;
    -fx-border-color: #3b4e72;
}

.amateur-root.dark-mode .ticket-action-secondary {
    -fx-background-color: #2d3d5b;
    -fx-border-color: #41567e;
    -fx-text-fill: #dce7ff;
}


